import{c as t,Q as i,j as o,m as a}from"./chunks/framework.CdiUUa3G.js";const p=JSON.parse('{"title":"PRD-010 — ISS Explorer","description":"","frontmatter":{},"headers":[],"relativePath":"prd/PRD-010.md","filePath":"prd/PRD-010.md"}'),r={name:"prd/PRD-010.md"};function s(l,e,n,d,c,u){return i(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="prd-010-—-iss-explorer" tabindex="-1">PRD-010 — ISS Explorer <a class="header-anchor" href="#prd-010-—-iss-explorer" aria-label="Permalink to &quot;PRD-010 — ISS Explorer&quot;">​</a></h1><p><em>Orrery · Product Requirements · v0.1 · May 2026</em></p><blockquote><p><strong>Status:</strong> Draft <strong>Sources:</strong> PRD-005 (Earth Orbit) for the orbital-context anchor; module-by-module ISS technical literature <strong>Audiences:</strong> curious learner, STEM student, space enthusiast (PA §audiences) <strong>Promises:</strong> real mission data fully attributed, educational at every level (PA §promises) <strong>Principles:</strong> physics first, attribution is design (PA §principles) <strong>Why this is a PRD:</strong> The ISS is the largest, most complex, longest-occupied human spacecraft ever flown. On <code>/earth</code> today, the station is a single dot orbiting Earth. That dot collapses thirty years of international engineering into one pixel. This PRD defines a peer screen — <code>/iss</code> — that opens that pixel into a navigable, rotatable 3D model where every module is a clickable surface with its own history, builder, launch, and gallery.</p></blockquote><p>A student arrives at <code>/iss</code>. The full station rotates slowly in the centre of the screen — 109 m end-to-end, solar arrays angled, every truss segment visible. They drag to rotate, reveal the Russian segment on the back. They click <em>Zarya</em>. The panel opens: &quot;Functional Cargo Block · Russia (Khrunichev / NASA-funded) · launched 1998 on Proton-K · the first ISS module in orbit.&quot; They click <em>Destiny</em>. &quot;US laboratory module · NASA · launched 2001 on STS-98 Atlantis · the primary US science workspace.&quot; A capability ladder unfolds module by module, builder by builder, launch by launch.</p><hr><h2 id="§why" tabindex="-1">§why <a class="header-anchor" href="#§why" aria-label="Permalink to &quot;§why&quot;">​</a></h2><p>The International Space Station is the most expensive object humans have ever built (~$150 B over 30 years), the longest-running human-occupied space habitat (continuous since November 2000), and the largest international engineering collaboration in history (5 space agencies, 15 countries). Reducing it to &quot;ISS · LEO · 408 km&quot; on <code>/earth</code> is an attribution failure of PA §principles (&quot;attribution is design&quot;).</p><p>A dedicated <code>/iss</code> page lets us tell the actual story:</p><ul><li><strong>Every module has a builder.</strong> Zvezda was built in Russia from a Soviet-era Mir-2 core. Destiny was built by Boeing in Huntsville. Kibo was built by Mitsubishi for JAXA. Columbus was built by Airbus for ESA. Each builder is a contribution to space-nation history.</li><li><strong>Every module has a launch.</strong> The shuttle launched most US modules; Proton launched the Russian core; H-II Transfer Vehicle delivered Kibo&#39;s external pallet. The launch vehicle history is itself the rocket-roster story (PRD-002).</li><li><strong>Every module has a function.</strong> Pressurised lab, airlock, cupola, sleeping quarters, exercise bay, robotic arm. The function history is the engineering history.</li></ul><p>A 3D model that lets users <em>find</em> and <em>click</em> each module turns the ISS from an abstract orbiting dot into a physical artefact whose every part has a story.</p><hr><h2 id="§audiences" tabindex="-1">§audiences <a class="header-anchor" href="#§audiences" aria-label="Permalink to &quot;§audiences&quot;">​</a></h2><p><strong>The curious learner</strong> rotates the station to find the <em>Cupola</em>. They click. They learn it has seven windows, including the largest single window ever flown in space. They see a photo of an astronaut framed in it.</p><p><strong>The STEM student</strong> uses /iss to ground &quot;what&#39;s actually on the station.&quot; They click <em>Tranquility</em> and learn the ECLSS (life support) is housed there. They click <em>Quest</em> and learn what an EVA airlock is and why it&#39;s separate from the docking ports.</p><p><strong>The space enthusiast</strong> uses it as a complete reference: every module, every launch date, every assembly sequence number, every spacewalk count, every crew handover.</p><hr><h2 id="§promises" tabindex="-1">§promises <a class="header-anchor" href="#§promises" aria-label="Permalink to &quot;§promises&quot;">​</a></h2><ol><li><strong>Every pressurised module is plotted, clickable, and panelled.</strong> ~16 modules currently make up the ISS. Each gets its own detail.</li><li><strong>Every module&#39;s panel mirrors the mission-panel pattern</strong> — OVERVIEW · GALLERY · LEARN tabs (matching <code>/missions</code>, <code>/moon</code>, <code>/mars</code>).</li><li><strong>The 3D model is interactively navigable.</strong> Drag to rotate, pinch to zoom, click any pressurised module or external truss segment.</li><li><strong>The orbital context is preserved.</strong> From <code>/iss</code>, the user can switch back to <code>/earth</code> and find the station&#39;s current orbit immediately. The two screens are designed to complement, not duplicate.</li><li><strong>Locale-aware</strong> per ADR-017.</li></ol><hr><h2 id="§scope" tabindex="-1">§scope <a class="header-anchor" href="#§scope" aria-label="Permalink to &quot;§scope&quot;">​</a></h2><h3 id="in-scope-v1" tabindex="-1">In scope (V1) <a class="header-anchor" href="#in-scope-v1" aria-label="Permalink to &quot;In scope (V1)&quot;">​</a></h3><p><strong>Default view: 3D ISS model.</strong></p><ul><li>Centred, slowly rotating model of the ISS (matching the reference photograph orientation: solar arrays horizontal, US segment forward).</li><li>Lit from a notional Sun direction so panels and trusses cast shadows for depth.</li><li>Earth backdrop optional (V1: black space; V1.5: Earth limb visible behind).</li><li>Module bodies rendered as clickable meshes; trusses as a single grouped backdrop unless V1 budget allows per-segment clickability.</li></ul><p><strong>Modules to plot (V1 list).</strong> Pressurised + key external structures:</p><table tabindex="0"><thead><tr><th>Module</th><th>Builder</th><th>Launch</th><th>Year</th><th>Function</th></tr></thead><tbody><tr><td>Zarya (FGB)</td><td>Khrunichev (Russia, NASA-funded)</td><td>Proton-K</td><td>1998</td><td>First module · functional cargo block</td></tr><tr><td>Unity (Node 1)</td><td>Boeing</td><td>STS-88</td><td>1998</td><td>First US node · 6 docking ports</td></tr><tr><td>Zvezda (Service Module)</td><td>Khrunichev / Energia</td><td>Proton-K</td><td>2000</td><td>Living quarters · attitude control</td></tr><tr><td>Destiny</td><td>Boeing</td><td>STS-98</td><td>2001</td><td>US laboratory</td></tr><tr><td>Quest</td><td>Boeing</td><td>STS-104</td><td>2001</td><td>EVA airlock</td></tr><tr><td>Pirs</td><td>RKK Energia</td><td>Soyuz-U</td><td>2001 (de-orbited 2021)</td><td>Russian docking + airlock (legacy)</td></tr><tr><td>Harmony (Node 2)</td><td>Thales Alenia (Italy, ESA → NASA)</td><td>STS-120</td><td>2007</td><td>US segment forward node</td></tr><tr><td>Columbus</td><td>Airbus (Germany, ESA)</td><td>STS-122</td><td>2008</td><td>ESA laboratory</td></tr><tr><td>Kibo</td><td>Mitsubishi (Japan, JAXA)</td><td>STS-123/124/127</td><td>2008–2009</td><td>Japanese laboratory complex</td></tr><tr><td>Tranquility (Node 3)</td><td>Thales Alenia (Italy, ESA → NASA)</td><td>STS-130</td><td>2010</td><td>Life support · exercise</td></tr><tr><td>Cupola</td><td>Thales Alenia (Italy, ESA → NASA)</td><td>STS-130</td><td>2010</td><td>7-window observation deck</td></tr><tr><td>Rassvet</td><td>RKK Energia</td><td>STS-132</td><td>2010</td><td>Russian docking compartment</td></tr><tr><td>Leonardo (PMM)</td><td>Thales Alenia (ESA / NASA)</td><td>STS-133</td><td>2011</td><td>Permanent storage module</td></tr><tr><td>BEAM</td><td>Bigelow Aerospace</td><td>SpaceX CRS-8</td><td>2016</td><td>First inflatable habitat tech demo</td></tr><tr><td>Nauka</td><td>Khrunichev</td><td>Proton-M</td><td>2021</td><td>Russian multipurpose laboratory</td></tr><tr><td>Prichal</td><td>RKK Energia</td><td>Soyuz</td><td>2021</td><td>Russian docking node</td></tr></tbody></table><p>≈ 16 modules for V1. External structures listed but not individually clickable in V1: the Integrated Truss Segments (P0–P6, S0–S6), Canadarm2, the solar array wings.</p><p><strong>Panel structure</strong> (mirrors <code>/missions</code> and the new <code>/mars</code> PRD):</p><ul><li><strong>OVERVIEW</strong><ul><li>Module name (display + native name where different)</li><li>Builder + builder country</li><li>Operating agency</li><li>Launch vehicle + launch date + flight designation (e.g. &quot;STS-122&quot;)</li><li>First-of badge if applicable (&quot;first inflatable habitat in space&quot;)</li><li>Function summary</li><li>Editorial description (Crimson Pro italic, ≤ 150 words)</li></ul></li><li><strong>GALLERY</strong> — module photos: build-and-test on Earth, in-orbit during deployment, in-orbit during operation, astronaut photos taken inside. 4–8 photos per module from NASA Image API + Wikimedia. Existing per-category-manifest pattern (ADR-016 / panel-tabs convention).</li><li><strong>LEARN</strong> — INTRO / CORE / DEEP tiered links: <ul><li>INTRO: Wikipedia primer</li><li>CORE: NASA module fact sheet, ESA / JAXA / Roscosmos module page where applicable</li><li>DEEP: assembly-sequence papers, EVA reports, life-extension reviews</li></ul></li></ul><p><strong>3D interaction.</strong></p><ul><li>Single-finger drag → orbit camera around station.</li><li>Two-finger pinch → dolly in / out (clamped 0.6× → 3×).</li><li>Tap a module → opens the detail panel. Module pulses (subtle scale animation) while the panel is open.</li><li>Reset-camera button (top-right toggle cluster, matching the /explore convention) returns to the default reference orientation.</li></ul><p><strong>Mobile.</strong></p><ul><li>Same gesture set; bottom-sheet panel.</li><li>Pinch + drag work as expected at 375 px.</li><li>Module list (alphabetical) shown as a fall-back when the user prefers a list to a 3D pick.</li></ul><h3 id="out-of-scope-v1" tabindex="-1">Out of scope (V1) <a class="header-anchor" href="#out-of-scope-v1" aria-label="Permalink to &quot;Out of scope (V1)&quot;">​</a></h3><ul><li>Real-time ISS position over Earth. (That&#39;s <code>/earth</code>&#39;s responsibility — the dot orbiting in real time.) /iss is a <em>physical-form</em> explorer, not a tracking screen.</li><li>Crew rotation history (who&#39;s currently on board, expedition counts). V2.</li><li>Inside-the-station tour. The 3D model is exterior-only in V1. An interior walk-through is a beautiful V2 feature but adds significant model + texture work.</li><li>ROSA (Roll-Out Solar Arrays) and other ongoing upgrades plotted as clickable surfaces. V1 plots them in the model but doesn&#39;t offer per-array detail.</li><li>Decommissioning timeline and de-orbit narrative. The ISS is currently planned to de-orbit ~2030; a &quot;what comes after&quot; tab is V2.</li><li>Visiting-vehicles dock-undock animations. V2.</li></ul><hr><h2 id="§design-hints" tabindex="-1">§design hints <a class="header-anchor" href="#§design-hints" aria-label="Permalink to &quot;§design hints&quot;">​</a></h2><p><strong>Layout.</strong></p><ul><li>Full-bleed 3D viewport.</li><li>Top-left HUD cluster (matches /explore convention after the v0.4 HUD redesign): camera-reset, module-list toggle, view-mode toggle (3D vs alphabetical-list).</li><li>Detail panel: bottom sheet on mobile, right drawer on desktop (ADR-018).</li></ul><p><strong>Tokens.</strong> Same as the rest of the app:</p><ul><li>Bebas Neue for module names + section titles.</li><li>Space Mono for technical labels (launch vehicle, dates, dimensions).</li><li>Crimson Pro italic for editorial descriptions.</li><li>Agency colour for the builder badge in each panel header (Roscosmos red, NASA blue, ESA blue, JAXA blue, etc., per existing tokens).</li></ul><p><strong>Visual style.</strong></p><ul><li>Module meshes: low-poly but recognisable. Aim for 5–8 k tris per pressurised module, 30–50 k total for the assembled station including trusses + arrays.</li><li>Simple PBR materials: matte white for pressurised module skins, gold for MLI thermal blankets, blue tint for solar array panels, dark grey for truss + radiators.</li><li>Hover state: outline highlight (post-process) on the hovered module so the click target is unambiguous.</li></ul><p><strong>Model authoring.</strong></p><ul><li>Working baseline: NASA&#39;s open-source ISS GLTF model (NASA-3D Resources / NASA Open Source Agreement). License-checked, attribution captured per PA §principles.</li><li>Alternative: simplified original model authored in Blender to keep file size and tris budget tight. RFC-012 to settle.</li><li>Target initial-load: &lt; 4 MB compressed (gzipped GLB). Lazy-loaded only when the route is visited.</li></ul><hr><h2 id="§non-goals" tabindex="-1">§non-goals <a class="header-anchor" href="#§non-goals" aria-label="Permalink to &quot;§non-goals&quot;">​</a></h2><ul><li><strong>Not a Kerbal Space Program clone.</strong> No physics simulation of orbital mechanics for visiting vehicles. The model is a static-but-rotatable artefact, not a sim.</li><li><strong>Not a real-time tracker.</strong> /earth tracks; /iss explores form.</li><li><strong>Not a comprehensive station-history textbook.</strong> Each module&#39;s panel has ≤ 150 words of description. The deep history lives in the LEARN tab&#39;s external links.</li></ul><hr><h2 id="§technical-considerations" tabindex="-1">§technical considerations <a class="header-anchor" href="#§technical-considerations" aria-label="Permalink to &quot;§technical considerations&quot;">​</a></h2><ul><li><strong>3D model loading.</strong> GLTFLoader (Three.js r128 includes it). Lazy-loaded with a progress bar identical to /plan&#39;s porkchop loader. Component unmount disposes the geometry + materials per ADR-016 cleanup pattern.</li><li><strong>Picking.</strong> Raycaster against the module group. Trusses are a separate group with <code>userData.pickable = false</code> so they don&#39;t intercept clicks unless V2 adds truss-segment detail.</li><li><strong>Data shape.</strong><ul><li>New file <code>static/data/iss-modules.json</code>: array of <code>{ id, builder, builder_country, agency, launch_vehicle, launch_date, flight_designation, function, mass_kg, length_m, year_first_of?, links[] }</code>. Schema validated by ajv per ADR-019.</li><li>Locale overlays at <code>static/data/i18n/[locale]/iss-modules/[id].json</code> carrying <code>{ name, description, function }</code>.</li></ul></li><li><strong>Image manifests.</strong> New <code>iss-galleries.json</code> mirrors the existing <code>mission-galleries.json</code> / <code>moon-site-galleries.json</code> pattern. NASA Image API + Wikimedia Commons fetched at build per ADR-016.</li><li><strong>Routing.</strong> New route <code>/iss</code>. URL params: <code>?module=[id]</code> deep-links open with the panel pre-opened. <code>?view=list</code> falls back to a non-3D module list (accessibility / low-end-device path).</li><li><strong>Nav.</strong> Adding ISS to the nav cluster: tentatively <code>EXPLORE → MISSIONS → PLAN → FLY → EARTH → ISS → MOON → MARS</code> so the LEO orbital story (ISS) sits beside Earth. UXS-010 to settle.</li></ul><h3 id="performance-budget" tabindex="-1">Performance budget <a class="header-anchor" href="#performance-budget" aria-label="Permalink to &quot;Performance budget&quot;">​</a></h3><ul><li>Initial JS payload addition: &lt; 30 KB (route component + GLTFLoader is already in the Three.js bundle).</li><li>Initial model payload (lazy-loaded on route entry): &lt; 4 MB compressed.</li><li>Per-module gallery: lazy-loaded per panel open.</li><li>Animation frame target: 60 fps on mid-range mobile. The model is static — rotation is camera-only — so this should be comfortably achievable.</li></ul><hr><h2 id="§definition-of-done" tabindex="-1">§definition-of-done <a class="header-anchor" href="#§definition-of-done" aria-label="Permalink to &quot;§definition-of-done&quot;">​</a></h2><p>A locale is considered &quot;ISS-shipped&quot; when:</p><ul><li>[ ] All 16 V1 modules in §scope render in the 3D model and are individually clickable.</li><li>[ ] Each module has OVERVIEW · GALLERY · LEARN tabs populated.</li><li>[ ] Each module has at least one photo in GALLERY (build, deployment, or in-orbit).</li><li>[ ] Each module&#39;s LEARN tab has at least one INTRO link (Wikipedia) and one CORE link (NASA / agency fact sheet).</li><li>[ ] 3D model loads in &lt; 4 MB compressed and renders at ≥ 30 fps on a 2020-baseline mobile device.</li><li>[ ] Mobile (375 px) renders without horizontal scroll; pinch + drag work.</li><li>[ ] Reset-camera button returns to the default orientation.</li><li>[ ] <code>?module=[id]</code> deep-links open the panel pre-selected.</li><li>[ ] <code>?view=list</code> fallback renders a non-3D alphabetical list with the same panel structure (accessibility + low-end path).</li><li>[ ] No console errors on /iss or any deep-link.</li><li>[ ] Lighthouse accessibility ≥ 95.</li><li>[ ] E2e: tap a module → panel opens; close → module deselects; deep-link <code>/iss?module=cupola</code> opens with Cupola&#39;s panel.</li></ul><hr><h2 id="§what-comes-after" tabindex="-1">§what comes after <a class="header-anchor" href="#§what-comes-after" aria-label="Permalink to &quot;§what comes after&quot;">​</a></h2><p>V1.5+: orbital context inset (mini Earth + station orbit in the corner of the screen). V2: visiting-vehicle dock animations (Soyuz, Crew Dragon, Cygnus, Progress, Dream Chaser). V2: interior walk-through. V2: crew rotation timeline. V3: post-2030 successor stations (Axiom, Orbital Reef, Chinese CSS as a separate similar screen).</p><hr><p><em>Orrery · PRD-010 · Draft v0.1 · Update when scope or definition-of-done changes.</em></p>',61)])])}const m=t(r,[["render",s]]);export{p as __pageData,m as default};
